import anthropic
import json

client = anthropic.Anthropic()


def call(prompt: str, max_tokens: int = 400) -> str:
    return client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=max_tokens,
        temperature=0.0,
        messages=[{"role": "user", "content": prompt}],
    ).content[0].text.strip()


def verify_json_output(output: str, required_keys: list[str]) -> tuple[bool, str]:
    """External verifier: check that output is valid JSON with required keys."""
    try:
        data = json.loads(output)
        missing = [k for k in required_keys if k not in data]
        if missing:
            return False, f"Missing keys: {missing}"
        return True, "OK"
    except json.JSONDecodeError as e:
        return False, f"JSON parse error: {e}"


def refine_for_json(
    prompt: str, output: str, error_reason: str
) -> str:
    return call(
        f"The following prompt produced output that failed validation.\n"
        f"Prompt: {prompt}\n"
        f"Output: {output}\n"
        f"Error: {error_reason}\n\n"
        "Rewrite the prompt so the model outputs ONLY valid JSON with these exact keys: "
        "\"summary\", \"sentiment\", \"action_required\". Output ONLY the improved prompt."
    )


REQUIRED_KEYS = ["summary", "sentiment", "action_required"]
prompt = "Analyse this customer message and respond."
task_input = "I've been waiting 2 weeks for my refund. This is unacceptable!"

for iteration in range(5):
    output = call(f"{prompt}\n\nMessage: {task_input}")
    passed, reason = verify_json_output(output, REQUIRED_KEYS)
    print(f"Iter {iteration + 1}: {'PASS' if passed else 'FAIL'} — {reason}")
    if passed:
        print(f"Final output: {output}")
        break
    prompt = refine_for_json(prompt, output, reason)
else:
    print("Did not converge within 5 iterations.")
